SELECT * FROM experiments
WHERE created_by = 1
ORDER BY actual_cost DESC;

SELECT e.experiment_name, p.project_name
FROM experiments e
JOIN projects p ON e.project_id = p.project_id;

SELECT COUNT(DISTINCT user_id)
FROM access_logs
WHERE access_date > (SELECT start_date FROM projects WHERE project_name = 'Project Y');

SELECT run_id, experiment_id, run_number, input_number, result, x2, x1, u, start_time, end_time, notes, status, estimated_duration, actual_duration, cost, environment
FROM runs
WHERE run_id = 0;

SELECT experiment_name
FROM experiments
WHERE experiment_type_id = 0;

SELECT DISTINCT e.*
FROM experiments e
JOIN versions v ON e.experiment_id = v.experiment_id;

SELECT COUNT(*)
FROM experiments
WHERE created_date > '2023-01-01' AND project_id = 1;

SELECT r.experiment_id, r.run_id, (r.cost / e.actual_cost) as cost_ratio
FROM runs r
JOIN experiments e ON r.experiment_id = e.experiment_id;

SELECT * 
FROM runs 
WHERE cost > (SELECT AVG(cost) FROM runs);
